import{_ as i,c as e,o as a,ae as o}from"./chunks/framework.B7Y1jjX-.js";const c=JSON.parse('{"title":"第一章 简单句","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/学习/英语/语法句法/第一章 简单句.md","filePath":"generated-notes/学习/英语/语法句法/第一章 简单句.md"}'),t={name:"generated-notes/学习/英语/语法句法/第一章 简单句.md"};function r(n,l,s,d,u,h){return a(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="第一章-简单句" tabindex="-1">第一章 简单句 <a class="header-anchor" href="#第一章-简单句" aria-label="Permalink to &quot;第一章 简单句&quot;">​</a></h1><h3 id="句子基本结构" tabindex="-1">句子基本结构 <a class="header-anchor" href="#句子基本结构" aria-label="Permalink to &quot;句子基本结构&quot;">​</a></h3><p><strong>结构</strong>：一句话中只能有一个动词，其余的为非谓语形式，构成独立主格。在没有动词的时候要使用be动词来充当。 <strong>分类</strong>：</p><ul><li>主语+谓语</li><li>主语+谓语+宾语</li><li>主语+谓语+表语</li><li>主语+谓语+宾语+宾补</li><li>主语+谓语+宾语+宾语（间接）</li></ul><hr><h3 id="谓语和动词" tabindex="-1">谓语和动词 <a class="header-anchor" href="#谓语和动词" aria-label="Permalink to &quot;谓语和动词&quot;">​</a></h3><p><strong>谓语（动词）</strong>：在句子中有且仅有一个的、有时态和语态的系动词或者实义动词。谓语就是动词，动词就是谓语。一句话不能没有谓语</p><ul><li>系动词： <ul><li>be动词</li><li>表示变化的：grow fall turn get become</li><li>表示保持的：stand keep stay remain</li><li>表示感官的：lo ok sound taste smell feel（后面只能加形容词）</li><li>表示现象的：seem appear</li><li>表示结果的：prove</li></ul></li><li>实义动词</li></ul><p><strong>非谓语动词</strong>：与其对应的概念是谓语（动词），其本身并不是动词。需要使用 ing主动、ed被动或者to do目的 形式</p><p><strong>动词分类</strong>：</p><ul><li>实义动词：及物不及物不重要 <ul><li>及物动词：后面必须接宾语</li><li>不及物动词：后面要加宾语必须加介词，可不加宾语。没有被动形式</li></ul></li><li>系动词： <ul><li>be动词</li><li>表示变化的：grow fall turn get become</li><li>表示保持的：stand keep stay remain</li><li>表示感官的：look sound taste smell feel（后面只能加形容词）</li><li>表示现象的：seem appear</li><li>表示结果的：prove</li></ul></li><li>情态动词：表明说话人的主观感情态度。后加动词原形 <ul><li>对过去进行推测：情态动词+have done <ul><li>must have done：一定做某事</li><li>needn&#39;t have done：你没必要做</li><li>should have done：本应做某事，没做</li><li>could have done：本能做某事，但是没做，表示遗憾</li></ul></li><li>对现在进行推测：情态动词+have do</li></ul></li><li>助动词：帮助动词完成时态，语态，疑问，被动，否定和强调的构成 <ul><li>be：用来构成进行时和被动语态</li><li>do：do，dose，did用于构成疑问句和强调</li><li>have：have，has，had用于构成完成时</li><li>will：will，would用于构成将来时</li></ul></li></ul><p><strong>考研常考的动词时态</strong>：</p><ul><li>一般现在时</li><li>：do</li><li>一般过去时：动作发生在过去，在过去的某点时间。在动作发生在过去且具有精确的时间的时候使用（图表和举例）</li><li>现在完成时：动作发生在过去，在过去的某段时间（曾经，已经）</li><li>一般将来时：will do 主将从现</li><li>现在进行时：be ding（描述图画）</li><li>过去完成时：had done</li></ul><hr><h3 id="主语" tabindex="-1">主语 <a class="header-anchor" href="#主语" aria-label="Permalink to &quot;主语&quot;">​</a></h3><p><strong>成分</strong>：一句话不能没有主语。</p><ul><li>名词：handsomeness and hardwork are his characteristic 可数的名词在充当主语时要加the、a或者s</li><li>代词</li><li>非谓语动词：Being handsome and hard-working is his characteristic 使用非谓语做主语时，谓语用单数</li><li>从句 <strong>没有主语</strong>的时候，要使用：</li><li>it：必须和温度天气时间有关 <ul><li>it is hot outsiade</li><li>it is cold in Xuzhou now</li></ul></li><li>There be：和“有”有关的时候，翻译为有 <ul><li>there is a flower on his head</li><li>there are loads of people having affection for me</li></ul></li><li>使用被动： <ul><li>persistence must be pointed out to be essential to success</li><li>pollution is thought to be serious by an increasing number of people</li><li>respecting parents is argued to be great importance</li><li>measures should be taken by the government</li></ul></li><li>I或者You等</li></ul><hr><h3 id="宾语" tabindex="-1">宾语 <a class="header-anchor" href="#宾语" aria-label="Permalink to &quot;宾语&quot;">​</a></h3><p><strong>成分</strong>：其需要注意的东西和主语一样</p><ul><li>名词</li><li>代词</li><li>从句</li><li>非谓语动词</li></ul><hr><h3 id="表语" tabindex="-1">表语 <a class="header-anchor" href="#表语" aria-label="Permalink to &quot;表语&quot;">​</a></h3><p><strong>成分</strong>：</p><ul><li>名词</li><li>代词</li><li>从句</li><li>非谓语动词</li><li>形容词</li><li>介词和介词短语</li></ul><hr>',26)])])}const g=i(t,[["render",r]]);export{c as __pageData,g as default};
